const fruits = ['apple', 'banana', 'orange'];

// Add a fruit to the end
fruits.push('grape'); // ['apple', 'banana', 'orange', 'grape']

// Remove the last fruit
const lastFruit = fruits.pop(); // removes 'grape', fruits is now ['apple', 'banana', 'orange']

// Add a fruit to the beginning
fruits.unshift('mango'); // ['mango', 'apple', 'banana', 'orange']

// Remove the first fruit
const firstFruit = fruits.shift(); // removes 'mango', fruits: ['apple', 'banana', 'orange']

let person;
if (person !== undefined) {
  console.log(person.name);
} else {
  console.log('Person object is undefined');
}

let isDone: boolean = false;
let age: number = 25;
let userName: string = 'Alice';
let hobbies: string[] = ['Reading', 'Gaming'];

// Tuple allows you to express an array with fixed number of elements of specific types
let address: [string, number] = ['Main Street', 123];

// Enum helps to define a set of named constants
enum Color {
  Red,
  Green,
  Blue
}
let favoriteColor: Color = Color.Green;

interface Person {
  name: string;
  age: number;
}

const person: Person = { name: "Alice", age: 30 };

// Incorrect: "email" is not declared inside Person interface
// console.log(person.email); // Error: Property 'email' does not exist on type 'Person'

// Fix 1: Add property to interface
interface Person {
  name: string;
  age: number;
  email?: string; // optional property
}

const personWithEmail: Person = { name: "Bob", age: 25, email: "bob@example.com" };
console.log(personWithEmail.email); // Works fine

// Fix 2: Use type assertion if you know the property exists
const personWithExtra = person as Person & { email: string };
console.log(personWithExtra.email); // Be careful: only use if the property actually exists

